B.ZC=new A.j3(B.H8,"Qui sommes-nous ?","Agricheck est une entreprise malienne sp\xe9cialis\xe9e dans la d\xe9tection intelligente des maladies des plantes gr\xe2ce \xe0 l\u2019intelligence artificielle et aux technologies de surveillance agricole.\n\nNotre solution accompagne les agriculteurs, les coop\xe9ratives agricoles et les grandes exploitations dans l\u2019identification rapide des maladies des cultures afin d\u2019am\xe9liorer les rendements agricoles, r\xe9duire les pertes de r\xe9coltes et faciliter la prise de d\xe9cision.\n\nAgricheck contribue \xe0 la modernisation de l\u2019agriculture malienne en proposant des outils num\xe9riques accessibles, innovants et adapt\xe9s aux r\xe9alit\xe9s du terrain.",B.b_,null)
B.H7=new A.aI(61563,"MaterialIcons",!1)
B.La=s(["La d\xe9tection pr\xe9coce des maladies des plantes.","L\u2019analyse intelligente des images agricoles.","La surveillance des exploitations par drone.","La recommandation de traitements adapt\xe9s.","Le suivi continu de l\u2019\xe9tat des cultures.","Nous voulons rendre les technologies agricoles modernes accessibles \xe0 tous les producteurs."],t.s)
B.Zz=new A.j3(B.H7,"Notre mission","Notre mission est d\u2019aider les agriculteurs \xe0 prot\xe9ger leurs cultures gr\xe2ce \xe0 :",B.La,null)
B.Hk=new A.aI(62625,"MaterialIcons",!1)
B.ZD=new A.j3(B.Hk,"Notre vision","Devenir une r\xe9f\xe9rence de l\u2019Agritech en Afrique de l\u2019Ouest en d\xe9veloppant des solutions innovantes bas\xe9es sur l\u2019intelligence artificielle, les drones et l\u2019analyse des donn\xe9es agricoles.\n\nNotre ambition est de contribuer \xe0 la s\xe9curit\xe9 alimentaire, \xe0 l\u2019am\xe9lioration des rendements agricoles et au d\xe9veloppement durable du secteur agricole malien.",B.b_,null)
